   449→// Gets tracked changes AND
   450→fn get_status_of_files(
   451→    repo: &Repository,
   452→    working_log: &PersistedWorkingLog,
   453→    edited_filepaths: HashSet<String>,
   454→    skip_untracked: bool,
   455→) -> Result<Vec<String>, GitAiError> {
   456→    let mut files = Vec::new();
   457→
   458→    // Use porcelain v2 format to get status
   459→
   460→    let edited_filepaths_option = if edited_filepaths.is_empty() {
   461→        None
   462→    } else {
   463→        Some(&edited_filepaths)
   464→    };
   465→
   466→    let status_start = Instant::now();
   467→    let statuses = repo.status(edited_filepaths_option, skip_untracked)?;
   468→    debug_log(&format!(
   469→        "[BENCHMARK]   git status call took {:?}",
   470→        status_start.elapsed()
   471→    ));
   472→
   473→    for entry in statuses {
   474→        // Skip ignored files
   475→        if entry.kind == EntryKind::Ignored {
   476→            continue;
   477→        }
   478→
   479→        // Skip unmerged/conflicted files - we'll track them once the conflict is resolved
   480→        if entry.kind == EntryKind::Unmerged {
   481→            continue;
   482→        }
   483→
   484→        // Include files that have any change (staged or unstaged) or are untracked
   485→        let has_change = entry.staged != StatusCode::Unmodified
   486→            || entry.unstaged != StatusCode::Unmodified
   487→            || entry.kind == EntryKind::Untracked;
   488→
   489→        if has_change {
   490→            // For deleted files, check if they were text files in HEAD
   491→            let is_deleted =
   492→                entry.staged == StatusCode::Deleted || entry.unstaged == StatusCode::Deleted;
   493→
   494→            let is_text = if is_deleted {
   495→                is_text_file_in_head(repo, &entry.path)
   496→            } else {
   497→                is_text_file(working_log, &entry.path)
   498→            };
   499→
   500→            if is_text {
   501→                files.push(entry.path.clone());
   502→            }
   503→        }
   504→    }
   505→
   506→    Ok(files)
   507→}
