   540→                let normalized_path = normalize_to_posix(&entry.file);
   541→                if !files.contains(&normalized_path) {
   542→                    // Check if it's a text file before adding
   543→                    if is_text_file(working_log, &normalized_path) {
   544→                        files.insert(normalized_path);
   545→                    }
   546→                }
   547→            }
   548→        }
   549→    }
   550→    debug_log(&format!(
   551→        "[BENCHMARK]   Reading checkpoints in get_all_tracked_files took {:?}",
   552→        checkpoints_read_start.elapsed()
   553→    ));
   554→
   555→    let has_ai_checkpoints = if let Ok(working_log_data) = working_log.read_all_checkpoints() {
   556→        working_log_data.iter().any(|checkpoint| {
   557→            checkpoint.kind == CheckpointKind::AiAgent || checkpoint.kind == CheckpointKind::AiTab
   558→        })
   559→    } else {
   560→        false
   561→    };
   562→
   563→    let status_files_start = Instant::now();
   564→    let mut results_for_tracked_files = if is_pre_commit && !has_ai_checkpoints {
   565→        get_status_of_files(repo, working_log, files, true)?
   566→    } else {
   567→        get_status_of_files(repo, working_log, files, false)?
   568→    };
   569→    debug_log(&format!(
   570→        "[BENCHMARK]   get_status_of_files in get_all_tracked_files took {:?}",
   571→        status_files_start.elapsed()
   572→    ));
   573→
   574→    // Ensure to always include all dirty files
   575→    if let Some(ref dirty_files) = working_log.dirty_files {
   576→        for file_path in dirty_files.keys() {
   577→            // Normalize path separators to forward slashes
   578→            let normalized_path = normalize_to_posix(file_path);
   579→            // Only add if not already in the files list
   580→            if !results_for_tracked_files.contains(&normalized_path) {
   581→                // Check if it's a text file before adding
   582→                if is_text_file(working_log, &normalized_path) {
   583→                    results_for_tracked_files.push(normalized_path);
   584→                }
   585→            }
   586→        }
   587→    }
   588→
   589→    Ok(results_for_tracked_files)
   590→}
