   592→fn save_current_file_states(
   593→    working_log: &PersistedWorkingLog,
   594→    files: &[String],
   595→) -> Result<HashMap<String, String>, GitAiError> {
   596→    let read_start = Instant::now();
   597→
   598→    // Extract only the data we need (no cloning the entire working_log)
   599→    let blobs_dir = working_log.dir.join("blobs");
   600→    let repo_workdir = working_log.repo_workdir.clone();
   601→    let dirty_files = working_log.dirty_files.clone();
   602→
   603→    // Process files concurrently with a semaphore limiting to 8 at a time
   604→    let file_content_hashes = smol::block_on(async {
   605→        let semaphore = Arc::new(smol::lock::Semaphore::new(8));
   606→        let blobs_dir = Arc::new(blobs_dir);
   607→        let repo_workdir = Arc::new(repo_workdir);
   608→        let dirty_files = Arc::new(dirty_files);
   609→
   610→        let futures = files.iter().map(|file_path| {
   611→            let file_path = file_path.clone();
   612→            let blobs_dir = Arc::clone(&blobs_dir);
   613→            let repo_workdir = Arc::clone(&repo_workdir);
   614→            let dirty_files = Arc::clone(&dirty_files);
   615→            let semaphore = Arc::clone(&semaphore);
   616→
   617→            async move {
   618→                // Acquire semaphore permit
   619→                let _permit = semaphore.acquire().await;
   620→
   621→                // Read file content - check dirty_files first, then filesystem
   622→                let content = if let Some(ref dirty_map) = *dirty_files {
   623→                    dirty_map.get(&file_path).cloned()
   624→                } else {
   625→                    None
   626→                }
   627→                .unwrap_or_else(|| {
   628→                    // Construct absolute path
   629→                    let abs_path = if std::path::Path::new(&file_path).is_absolute() {
   630→                        file_path.clone()
   631→                    } else {
   632→                        repo_workdir.join(&file_path).to_string_lossy().to_string()
   633→                    };
   634→                    // Read from filesystem
   635→                    std::fs::read_to_string(&abs_path).unwrap_or_default()
   636→                });
   637→
   638→                // Create SHA256 hash of the content
   639→                let mut hasher = Sha256::new();
   640→                hasher.update(content.as_bytes());
   641→                let sha = format!("{:x}", hasher.finalize());
   642→
   643→                // Ensure blobs directory exists
   644→                std::fs::create_dir_all(&*blobs_dir)?;
   645→
   646→                // Write content to blob file
   647→                let blob_path = blobs_dir.join(&sha);
   648→                std::fs::write(blob_path, content)?;
   649→
   650→                Ok::<(String, String), GitAiError>((file_path, sha))
   651→            }
   652→        });
   653→
   654→        // Collect results from all concurrent operations
   655→        let results: Vec<Result<(String, String), GitAiError>> =
   656→            stream::iter(futures).buffer_unordered(8).collect().await;
   657→
   658→        // Convert results into HashMap
   659→        let mut file_content_hashes = HashMap::new();
   660→        for result in results {
   661→            let (file_path, content_hash) = result?;
   662→            file_content_hashes.insert(file_path, content_hash);
   663→        }
   664→
   665→        Ok::<HashMap<String, String>, GitAiError>(file_content_hashes)
   666→    })?;
   667→
   668→    Ok(file_content_hashes)
   669→}
