   671→fn get_checkpoint_entry_for_file(
   672→    file_path: String,
   673→    kind: CheckpointKind,
   674→    repo: Repository,
   675→    working_log: PersistedWorkingLog,
   676→    previous_checkpoints: Arc<Vec<Checkpoint>>,
   677→    file_content_hash: String,
   678→    author_id: Arc<String>,
   679→    head_commit_sha: Arc<Option<String>>,
   680→    head_tree_id: Arc<Option<String>>,
   681→    initial_attributions: Arc<HashMap<String, Vec<LineAttribution>>>,
   682→    ts: u128,
   683→) -> Result<Option<(WorkingLogEntry, FileLineStats)>, GitAiError> {
   684→    let feature_flag_inter_commit_move = Config::get().get_feature_flags().inter_commit_move;
   685→
   686→    let file_start = Instant::now();
   687→    let current_content = working_log
   688→        .read_current_file_content(&file_path)
   689→        .unwrap_or_default();
   690→
   691→    // Try to get previous state from checkpoints first
   692→    let from_checkpoint = previous_checkpoints.iter().rev().find_map(|checkpoint| {
   693→        checkpoint
   694→            .entries
   695→            .iter()
   696→            .find(|e| e.file == file_path)
   697→            .map(|entry| {
   698→                (
   699→                    working_log
   700→                        .get_file_version(&entry.blob_sha)
   701→                        .unwrap_or_default(),
   702→                    entry.attributions.clone(),
   703→                )
   704→            })
   705→    });
   706→
   707→    // Get INITIAL attributions for this file (needed early for the skip check)
   708→    let initial_attrs_for_file = initial_attributions
   709→        .get(&file_path)
   710→        .cloned()
   711→        .unwrap_or_default();
   712→
   713→    let is_from_checkpoint = from_checkpoint.is_some();
   714→    let (previous_content, prev_attributions) = if let Some((content, attrs)) = from_checkpoint {
   715→        // File exists in a previous checkpoint - use that
   716→        (content, attrs)
   717→    } else {
   718→        // File doesn't exist in any previous checkpoint - need to initialize from git + INITIAL
   719→        // Get previous content from HEAD tree
   720→        let previous_content = if let Some(tree_id) = head_tree_id.as_ref().as_ref() {
   721→            let head_tree = repo.find_tree(tree_id.clone()).ok();
   722→            if let Some(tree) = head_tree {
   723→                match tree.get_path(std::path::Path::new(&file_path)) {
   724→                    Ok(entry) => {
   725→                        if let Ok(blob) = repo.find_blob(entry.id()) {
   726→                            let blob_content = blob.content().unwrap_or_default();
   727→                            String::from_utf8_lossy(&blob_content).to_string()
   728→                        } else {
   729→                            String::new()
   730→                        }
   731→                    }
   732→                    Err(_) => String::new(),
   733→                }
   734→            } else {
   735→                String::new()
   736→            }
   737→        } else {
   738→            String::new()
   739→        };
   740→
   741→        // Skip if no changes, UNLESS we have INITIAL attributions for this file
   742→        // (in which case we need to create an entry to record those attributions)
   743→        if current_content == previous_content && initial_attrs_for_file.is_empty() {
   744→            return Ok(None);
   745→        }
   746→
   747→        // Build a set of lines covered by INITIAL attributions
   748→        let mut initial_covered_lines: HashSet<u32> = HashSet::new();
   749→        for attr in &initial_attrs_for_file {
   750→            for line in attr.start_line..=attr.end_line {
   751→                initial_covered_lines.insert(line);
   752→            }
   753→        }
   754→
   755→        // Start with INITIAL attributions (they win)
   756→        let mut prev_line_attributions = initial_attrs_for_file.clone();
   757→        let mut blamed_lines: HashSet<u32> = HashSet::new();
   758→
   759→        // Get blame for lines not in INITIAL
   760→        let blame_start = Instant::now();
   761→        let mut ai_blame_opts = GitAiBlameOptions::default();
   762→        ai_blame_opts.no_output = true;
   763→        ai_blame_opts.return_human_authors_as_human = true;
   764→        ai_blame_opts.use_prompt_hashes_as_names = true;
   765→        ai_blame_opts.newest_commit = head_commit_sha.as_ref().clone();
   766→        ai_blame_opts.oldest_date = Some(OLDEST_AI_BLAME_DATE.clone());
   767→        let ai_blame = if feature_flag_inter_commit_move {
   768→            repo.blame(&file_path, &ai_blame_opts).ok()
   769→        } else {
   770→            // When skipping blame, default all lines to "human"
   771→            let total_lines = previous_content.lines().count() as u32;
   772→            let mut line_authors: HashMap<u32, String> = HashMap::new();
   773→            for line_num in 1..=total_lines {
   774→                line_authors.insert(line_num, CheckpointKind::Human.to_str());
   775→            }
   776→            let prompt_records: HashMap<String, PromptRecord> = HashMap::new();
   777→            Some((line_authors, prompt_records))
   778→        };
   779→
   780→        debug_log(&format!(
   781→            "[BENCHMARK] Blame for {} took {:?}",
   782→            file_path,
   783→            blame_start.elapsed()
   784→        ));
   785→
   786→        // Add blame results for lines NOT covered by INITIAL
   787→        if let Some((blames, _)) = ai_blame {
   788→            for (line, author) in blames {
   789→                blamed_lines.insert(line);
   790→                // Skip if INITIAL already has this line
   791→                if initial_covered_lines.contains(&line) {
   792→                    continue;
   793→                }
   794→
   795→                // Skip human-authored lines - they should remain human
   796→                if author == CheckpointKind::Human.to_str() {
   797→                    continue;
   798→                }
   799→
   800→                prev_line_attributions.push(LineAttribution {
   801→                    start_line: line,
   802→                    end_line: line,
   803→                    author_id: author.clone(),
   804→                    overrode: None,
   805→                });
   806→            }
   807→        }
   808→
   809→        // For AI checkpoints, attribute any lines NOT in INITIAL and NOT returned by ai_blame
   810→        if kind != CheckpointKind::Human {
   811→            let total_lines = current_content.lines().count() as u32;
   812→            for line_num in 1..=total_lines {
   813→                if !initial_covered_lines.contains(&line_num) && !blamed_lines.contains(&line_num) {
   814→                    prev_line_attributions.push(LineAttribution {
   815→                        start_line: line_num,
   816→                        end_line: line_num,
   817→                        author_id: author_id.as_ref().clone(),
   818→                        overrode: None,
   819→                    });
   820→                }
   821→            }
   822→        }
   823→
   824→        // For INITIAL attributions, we need to use current_content (not previous_content)
   825→        // because INITIAL line numbers refer to the current state of the file
   826→        let content_for_line_conversion = if !initial_attrs_for_file.is_empty() {
   827→            &current_content
   828→        } else {
   829→            &previous_content
   830→        };
   831→
   832→        // Convert any line attributions to character attributions
   833→        let prev_attributions =
   834→            crate::authorship::attribution_tracker::line_attributions_to_attributions(
   835→                &prev_line_attributions,
   836→                content_for_line_conversion,
   837→                INITIAL_ATTRIBUTION_TS,
   838→            );
   839→
   840→        // When we have INITIAL attributions, they describe the current state of the file.
   841→        // We need to pass current_content as previous_content so the attributions are preserved.
   842→        // The tracker will see no changes and preserve the INITIAL attributions.
   843→        let adjusted_previous = if !initial_attrs_for_file.is_empty() {
   844→            current_content.clone()
   845→        } else {
   846→            previous_content
   847→        };
   848→
   849→        (adjusted_previous, prev_attributions)
   850→    };
   851→
   852→    // Skip if no changes (but we already checked this earlier, accounting for INITIAL attributions)
   853→    // For files from previous checkpoints, check if content has changed
   854→    if is_from_checkpoint && current_content == previous_content {
   855→        return Ok(None);
   856→    }
   857→
   858→    let (entry, stats) = make_entry_for_file(
   859→        &file_path,
   860→        &file_content_hash,
   861→        author_id.as_ref(),
   862→        &previous_content,
   863→        &prev_attributions,
   864→        &current_content,
   865→        ts,
   866→    )?;
   867→    debug_log(&format!(
   868→        "[BENCHMARK] Processing file {} took {:?}",
   869→        file_path,
   870→        file_start.elapsed()
   871→    ));
   872→    Ok(Some((entry, stats)))
   873→}
   874→
   875→async fn get_checkpoint_entries(
   876→    kind: CheckpointKind,
   877→    repo: &Repository,
   878→    working_log: &PersistedWorkingLog,
   879→    files: &[String],
   880→    file_content_hashes: &HashMap<String, String>,
   881→    previous_checkpoints: &[Checkpoint],
   882→    agent_run_result: Option<&AgentRunResult>,
   883→    ts: u128,
   884→) -> Result<(Vec<WorkingLogEntry>, Vec<FileLineStats>), GitAiError> {
   885→    let entries_fn_start = Instant::now();
   886→
   887→    // Read INITIAL attributions from working log (empty if file doesn't exist)
   888→    let initial_read_start = Instant::now();
   889→    let initial_data = working_log.read_initial_attributions();
   890→    let initial_attributions = initial_data.files;
   891→    debug_log(&format!(
   892→        "[BENCHMARK] Reading initial attributions took {:?}",
   893→        initial_read_start.elapsed()
   894→    ));
   895→
   896→    // Determine author_id based on checkpoint kind and agent_id
   897→    let author_id = if kind != CheckpointKind::Human {
   898→        // For AI checkpoints, use session hash
   899→        agent_run_result
   900→            .map(|result| {
   901→                crate::authorship::authorship_log_serialization::generate_short_hash(
   902→                    &result.agent_id.id,
   903→                    &result.agent_id.tool,
   904→                )
   905→            })
   906→            .unwrap_or_else(|| kind.to_str())
   907→    } else {
   908→        // For human checkpoints, use checkpoint kind string
   909→        kind.to_str()
   910→    };
   911→
   912→    // Get HEAD commit info for git operations
   913→    let head_commit = repo
   914→        .head()
   915→        .ok()
   916→        .and_then(|h| h.target().ok())
   917→        .and_then(|oid| repo.find_commit(oid).ok());
   918→    let head_commit_sha = head_commit.as_ref().map(|c| c.id().to_string());
   919→    let head_tree_id = head_commit
   920→        .as_ref()
   921→        .and_then(|c| c.tree().ok())
   922→        .map(|t| t.id().to_string());
   923→
   924→    const MAX_CONCURRENT: usize = 30;
   925→
   926→    // Create a semaphore to limit concurrent tasks
   927→    let semaphore = Arc::new(smol::lock::Semaphore::new(MAX_CONCURRENT));
   928→
   929→    // Move checkpoint data to Arc once, outside the loop to avoid repeated allocations
   930→    let previous_checkpoints = Arc::new(previous_checkpoints.to_vec());
   931→
   932→    // Move other repeated allocations outside the loop
   933→    let author_id = Arc::new(author_id);
   934→    let head_commit_sha = Arc::new(head_commit_sha);
   935→    let head_tree_id = Arc::new(head_tree_id);
   936→    let initial_attributions = Arc::new(initial_attributions);
   937→
   938→    // Spawn tasks for each file
   939→    let spawn_start = Instant::now();
   940→    let mut tasks = Vec::new();
   941→
   942→    for file_path in files {
   943→        let file_path = file_path.clone();
   944→        let repo = repo.clone();
   945→        let working_log = working_log.clone();
   946→        let previous_checkpoints = Arc::clone(&previous_checkpoints);
   947→        let author_id = Arc::clone(&author_id);
   948→        let head_commit_sha = Arc::clone(&head_commit_sha);
   949→        let head_tree_id = Arc::clone(&head_tree_id);
   950→        let blob_sha = file_content_hashes
   951→            .get(&file_path)
   952→            .cloned()
   953→            .unwrap_or_default();
   954→        let initial_attributions = Arc::clone(&initial_attributions);
   955→        let semaphore = Arc::clone(&semaphore);
   956→        let kind = kind.clone();
   957→
   958→        let task = smol::spawn(async move {
   959→            // Acquire semaphore permit to limit concurrency
   960→            let _permit = semaphore.acquire().await;
   961→
   962→            // Wrap all the blocking git operations in smol::unblock
   963→            smol::unblock(move || {
   964→                get_checkpoint_entry_for_file(
   965→                    file_path,
   966→                    kind,
   967→                    repo,
   968→                    working_log,
   969→                    previous_checkpoints,
   970→                    blob_sha,
   971→                    author_id.clone(),
   972→                    head_commit_sha.clone(),
   973→                    head_tree_id.clone(),
   974→                    initial_attributions.clone(),
   975→                    ts,
   976→                )
   977→            })
   978→            .await
   979→        });
   980→
   981→        tasks.push(task);
   982→    }
   983→    debug_log(&format!(
   984→        "[BENCHMARK] Spawning {} tasks took {:?}",
   985→        tasks.len(),
   986→        spawn_start.elapsed()
   987→    ));
   988→
   989→    // Await all tasks concurrently
   990→    let await_start = Instant::now();
   991→    let results = futures::future::join_all(tasks).await;
   992→    debug_log(&format!(
   993→        "[BENCHMARK] Awaiting {} tasks took {:?}",
   994→        results.len(),
   995→        await_start.elapsed()
   996→    ));
   997→
   998→    // Process results
   999→    let process_start = Instant::now();
  1000→    let results_count = results.len();
  1001→    let mut entries = Vec::new();
  1002→    let mut file_stats = Vec::new();
  1003→    for result in results {
  1004→        match result {
  1005→            Ok(Some((entry, stats))) => {
  1006→                entries.push(entry);
  1007→                file_stats.push(stats);
  1008→            }
  1009→            Ok(None) => {} // File had no changes
  1010→            Err(e) => return Err(e),
  1011→        }
  1012→    }
  1013→    debug_log(&format!(
  1014→        "[BENCHMARK] Processing {} results took {:?}",
  1015→        results_count,
  1016→        process_start.elapsed()
  1017→    ));
  1018→    debug_log(&format!(
  1019→        "[BENCHMARK] get_checkpoint_entries function total took {:?}",
  1020→        entries_fn_start.elapsed()
  1021→    ));
  1022→
  1023→    Ok((entries, file_stats))
  1024→}
  1025→
  1026→fn make_entry_for_file(
  1027→    file_path: &str,
  1028→    blob_sha: &str,
  1029→    author_id: &str,
  1030→    previous_content: &str,
  1031→    previous_attributions: &Vec<Attribution>,
  1032→    content: &str,
  1033→    ts: u128,
  1034→) -> Result<(WorkingLogEntry, FileLineStats), GitAiError> {
  1035→    let tracker = AttributionTracker::new();
  1036→
  1037→    let fill_start = Instant::now();
  1038→    let filled_in_prev_attributions = tracker.attribute_unattributed_ranges(
  1039→        previous_content,
  1040→        previous_attributions,
  1041→        &CheckpointKind::Human.to_str(),
  1042→        ts - 1,
  1043→    );
  1044→    debug_log(&format!(
  1045→        "[BENCHMARK]   attribute_unattributed_ranges for {} took {:?}",
  1046→        file_path,
  1047→        fill_start.elapsed()
  1048→    ));
  1049→
  1050→    let update_start = Instant::now();
  1051→    let new_attributions = tracker.update_attributions(
  1052→        previous_content,
  1053→        content,
  1054→        &filled_in_prev_attributions,
  1055→        author_id,
  1056→        ts,
  1057→    )?;
  1058→    debug_log(&format!(
  1059→        "[BENCHMARK]   update_attributions for {} took {:?}",
  1060→        file_path,
  1061→        update_start.elapsed()
  1062→    ));
  1063→
  1064→    // TODO Consider discarding any "uncontentious" attributions for the human author. Any human attributions that do not share a line with any other author's attributions can be discarded.
  1065→    // let filtered_attributions = crate::authorship::attribution_tracker::discard_uncontentious_attributions_for_author(&new_attributions, &CheckpointKind::Human.to_str());
  1066→
  1067→    let line_attr_start = Instant::now();
  1068→    let line_attributions =
  1069→        crate::authorship::attribution_tracker::attributions_to_line_attributions(
  1070→            &new_attributions,
  1071→            content,
  1072→        );
  1073→    debug_log(&format!(
  1074→        "[BENCHMARK]   attributions_to_line_attributions for {} took {:?}",
  1075→        file_path,
  1076→        line_attr_start.elapsed()
  1077→    ));
  1078→
  1079→    // Compute line stats while we already have both contents in memory
  1080→    let stats_start = Instant::now();
  1081→    let line_stats = compute_file_line_stats(previous_content, content);
  1082→    debug_log(&format!(
  1083→        "[BENCHMARK]   compute_file_line_stats for {} took {:?}",
  1084→        file_path,
  1085→        stats_start.elapsed()
  1086→    ));
  1087→
  1088→    let entry = WorkingLogEntry::new(
  1089→        file_path.to_string(),
  1090→        blob_sha.to_string(),
  1091→        new_attributions,
  1092→        line_attributions,
  1093→    );
  1094→
  1095→    Ok((entry, line_stats))
  1096→}
  1097→
  1098→/// Compute line statistics for a single file by diffing previous and current content
  1099→fn compute_file_line_stats(previous_content: &str, current_content: &str) -> FileLineStats {
  1100→    let mut stats = FileLineStats::default();
  1101→
  1102→    // Use imara_diff to count line changes (matches git's diff algorithm)
  1103→    let changes = compute_line_changes(previous_content, current_content);
  1104→    for change in changes {
  1105→        match change.tag() {
  1106→            LineChangeTag::Insert => {
  1107→                let non_whitespace_lines = change
  1108→                    .value()
  1109→                    .lines()
  1110→                    .filter(|line| !line.trim().is_empty())
  1111→                    .count() as u32;
  1112→                stats.additions += change.value().lines().count() as u32;
  1113→                stats.additions_sloc += non_whitespace_lines;
  1114→            }
  1115→            LineChangeTag::Delete => {
  1116→                let non_whitespace_lines = change
  1117→                    .value()
  1118→                    .lines()
  1119→                    .filter(|line| !line.trim().is_empty())
  1120→                    .count() as u32;
  1121→                stats.deletions += change.value().lines().count() as u32;
  1122→                stats.deletions_sloc += non_whitespace_lines;
  1123→            }
  1124→            LineChangeTag::Equal => {}
  1125→        }
  1126→    }
  1127→
  1128→    stats
  1129→}
  1130→
  1131→/// Aggregate line statistics from individual file stats
  1132→/// This avoids redundant diff computation since stats are already computed during entry creation
  1133→fn compute_line_stats(
  1134→    file_stats: &[FileLineStats],
  1135→) -> Result<crate::authorship::working_log::CheckpointLineStats, GitAiError> {
  1136→    let mut stats = crate::authorship::working_log::CheckpointLineStats::default();
  1137→
  1138→    // Aggregate line stats from all files
  1139→    for file_stat in file_stats {
  1140→        stats.additions += file_stat.additions;
  1141→        stats.deletions += file_stat.deletions;
  1142→        stats.additions_sloc += file_stat.additions_sloc;
  1143→        stats.deletions_sloc += file_stat.deletions_sloc;
  1144→    }
  1145→
  1146→    Ok(stats)
  1147→}
