  1515→fn is_text_file(working_log: &PersistedWorkingLog, path: &str) -> bool {
  1516→    // Normalize path for dirty_files lookup
  1517→    let normalized_path = normalize_to_posix(path);
  1518→    let skip_metadata_check = working_log
  1519→        .dirty_files
  1520→        .as_ref()
  1521→        .map(|m| m.contains_key(&normalized_path))
  1522→        .unwrap_or(false);
  1523→
  1524→    if !skip_metadata_check {
  1525→        if let Ok(metadata) = std::fs::metadata(working_log.to_repo_absolute_path(&normalized_path))
  1526→        {
  1527→            if !metadata.is_file() {
  1528→                return false;
  1529→            }
  1530→        } else {
  1531→            return false; // If metadata can't be read, treat as non-text
  1532→        }
  1533→    }
  1534→
  1535→    working_log
  1536→        .read_current_file_content(&normalized_path)
  1537→        .map(|content| !content.chars().any(|c| c == '\0'))
  1538→        .unwrap_or(false)
  1539→}
  1540→
  1541→fn is_text_file_in_head(repo: &Repository, path: &str) -> bool {
  1542→    // For deleted files, check if they were text files in HEAD
  1543→    let head_commit = match repo
  1544→        .head()
  1545→        .ok()
  1546→        .and_then(|h| h.target().ok())
  1547→        .and_then(|oid| repo.find_commit(oid).ok())
  1548→    {
  1549→        Some(commit) => commit,
  1550→        None => return false,
  1551→    };
  1552→
  1553→    let head_tree = match head_commit.tree().ok() {
  1554→        Some(tree) => tree,
  1555→        None => return false,
  1556→    };
  1557→
  1558→    match head_tree.get_path(std::path::Path::new(path)) {
  1559→        Ok(entry) => {
  1560→            if let Ok(blob) = repo.find_blob(entry.id()) {
  1561→                // Consider a file text if it contains no null bytes
  1562→                let blob_content = match blob.content() {
  1563→                    Ok(content) => content,
  1564→                    Err(_) => return false,
  1565→                };
  1566→                !blob_content.contains(&0)
  1567→            } else {
  1568→                false
  1569→            }
  1570→        }
  1571→        Err(_) => false,
  1572→    }
  1573→}
