  1575→/// Upsert a checkpoint prompt to the internal database
  1576→fn upsert_checkpoint_prompt_to_db(
  1577→    checkpoint: &Checkpoint,
  1578→    workdir: String,
  1579→    commit_sha: Option<String>,
  1580→) -> Result<(), GitAiError> {
  1581→    use crate::authorship::internal_db::{InternalDatabase, PromptDbRecord};
  1582→
  1583→    let record = PromptDbRecord::from_checkpoint(checkpoint, Some(workdir), commit_sha)
  1584→        .ok_or_else(|| {
  1585→            GitAiError::Generic("Failed to create prompt record from checkpoint".to_string())
  1586→        })?;
  1587→
  1588→    let db = InternalDatabase::global()?;
  1589→    let mut db_guard = db
  1590→        .lock()
  1591→        .map_err(|e| GitAiError::Generic(format!("Failed to lock database: {}", e)))?;
  1592→
  1593→    db_guard.upsert_prompt(&record)?;
  1594→
  1595→    Ok(())
  1596→}
