    99→// Uses checkpoint.GitStore.WriteCommitted for the git operations.
   100→func (s *ManualCommitStrategy) CondenseSession(repo *git.Repository, checkpointID id.CheckpointID, state *SessionState) (*CondenseResult, error) {
