   139→		CheckpointsCount:       state.CheckpointCount,
   140→		EphemeralBranch:        shadowBranchName,
   141→		AuthorName:             authorName,
   142→		AuthorEmail:            authorEmail,
   143→		Agent:                  state.AgentType,
   144→		TranscriptUUIDAtStart:  state.TranscriptUUIDAtStart,
   145→		TranscriptLinesAtStart: state.TranscriptLinesAtStart,
