   151→	return &CondenseResult{
   152→		CheckpointID:         checkpointID,
   153→		SessionID:            state.SessionID,
   154→		CheckpointsCount:     state.CheckpointCount,
   155→		FilesTouched:         sessionData.FilesTouched,
   156→		TotalTranscriptLines: sessionData.FullTranscriptLines,
   157→	}, nil
