   159→
   160→// extractSessionData extracts session data from the shadow branch.
   161→// filesTouched is the list of files tracked during the session (from SessionState.FilesTouched).
   162→// agentType identifies the agent (e.g., "Gemini CLI", "Claude Code") to determine transcript format.
   163→func (s *ManualCommitStrategy) extractSessionData(repo *git.Repository, shadowRef plumbing.Hash, sessionID string, filesTouched []string, agentType agent.AgentType) (*ExtractedSessionData, error) {
   164→	commit, err := repo.CommitObject(shadowRef)
   165→	if err != nil {
   166→		return nil, fmt.Errorf("failed to get commit object: %w", err)
   167→	}
   168→
   169→	tree, err := commit.Tree()
   170→	if err != nil {
   171→		return nil, fmt.Errorf("failed to get commit tree: %w", err)
   172→	}
   173→
   174→	data := &ExtractedSessionData{}
   175→	// sessionID is already an "entire session ID" (with date prefix), so construct path directly
   176→	// Don't use paths.SessionMetadataDir which would add another date prefix
   177→	metadataDir := paths.EntireMetadataDir + "/" + sessionID
   178→
   179→	// Extract transcript
   180→	var fullTranscript string
   181→	if file, fileErr := tree.File(metadataDir + "/" + paths.TranscriptFileName); fileErr == nil {
   182→		if content, contentErr := file.Contents(); contentErr == nil {
   183→			fullTranscript = content
   184→		}
   185→	} else if file, fileErr := tree.File(metadataDir + "/" + paths.TranscriptFileNameLegacy); fileErr == nil {
   186→		if content, contentErr := file.Contents(); contentErr == nil {
   187→			fullTranscript = content
   188→		}
   189→	}
   190→
   191→	// Process transcript based on agent type
   192→	if fullTranscript != "" {
   193→		// Check if this is a Gemini CLI transcript (JSON format, not JSONL)
   194→		isGeminiFormat := agentType == agent.AgentTypeGemini || isGeminiJSONTranscript(fullTranscript)
   195→
   196→		if isGeminiFormat {
   197→			// Gemini uses JSON format with a "messages" array
   198→			data.Transcript = []byte(fullTranscript)
   199→			data.FullTranscriptLines = 1 // JSON is a single "line"
   200→			data.Prompts = extractUserPromptsFromGeminiJSON(fullTranscript)
   201→			data.Context = generateContextFromPrompts(data.Prompts)
   202→		} else {
   203→			// Claude Code and others use JSONL format (one JSON object per line)
   204→			allLines := strings.Split(fullTranscript, "\n")
   205→
   206→			// Trim trailing empty lines (from final \n in JSONL)
   207→			for len(allLines) > 0 && strings.TrimSpace(allLines[len(allLines)-1]) == "" {
   208→				allLines = allLines[:len(allLines)-1]
   209→			}
   210→
   211→			data.FullTranscriptLines = len(allLines)
   212→
   213→			// Always store the full transcript for complete session history
   214→			data.Transcript = []byte(strings.Join(allLines, "\n"))
   215→
   216→			// Extract prompts from the full transcript
   217→			data.Prompts = extractUserPromptsFromLines(allLines)
   218→
   219→			// Generate context from prompts
   220→			data.Context = generateContextFromPrompts(data.Prompts)
   221→		}
   222→	}
   223→
   224→	// Use tracked files from session state (not all files in tree)
   225→	data.FilesTouched = filesTouched
   226→
   227→	// Calculate token usage from the extracted transcript portion
   228→	if len(data.Transcript) > 0 {
   229→		transcriptLines, err := claudecode.ParseTranscript(data.Transcript)
   230→		if err == nil && len(transcriptLines) > 0 {
   231→			data.TokenUsage = claudecode.CalculateTokenUsage(transcriptLines)
   232→		}
   233→	}
   234→
   235→	return data, nil
   236→}
   237→
   238→// isGeminiJSONTranscript detects if the transcript is in Gemini's JSON format.
   239→// Gemini transcripts start with a JSON object containing a "messages" array.
   240→func isGeminiJSONTranscript(content string) bool {
   241→	content = strings.TrimSpace(content)
   242→	// Quick check: Gemini JSON starts with { and contains "messages"
   243→	if !strings.HasPrefix(content, "{") {
   244→		return false
   245→	}
   246→	// Try to parse as Gemini format
   247→	var transcript struct {
   248→		Messages []json.RawMessage `json:"messages"`
   249→	}
   250→	if err := json.Unmarshal([]byte(content), &transcript); err != nil {
   251→		return false
   252→	}
   253→	return len(transcript.Messages) > 0
   254→}
   255→
   256→// extractUserPromptsFromGeminiJSON extracts user prompts from Gemini's JSON transcript format.
   257→// Gemini transcripts are structured as: {"messages": [{"type": "user", "content": "..."}, ...]}
   258→func extractUserPromptsFromGeminiJSON(content string) []string {
   259→	var transcript struct {
   260→		Messages []struct {
   261→			Type    string `json:"type"`
   262→			Content string `json:"content"`
   263→		} `json:"messages"`
   264→	}
   265→
   266→	if err := json.Unmarshal([]byte(content), &transcript); err != nil {
   267→		return nil
   268→	}
   269→
   270→	var prompts []string
   271→	for _, msg := range transcript.Messages {
   272→		if msg.Type == "user" && msg.Content != "" {
   273→			// Strip IDE context tags for consistency with Claude Code handling
   274→			cleaned := textutil.StripIDEContextTags(msg.Content)
   275→			if cleaned != "" {
   276→				prompts = append(prompts, cleaned)
   277→			}
   278→		}
   279→	}
   280→
   281→	return prompts
   282→}
   283→
   284→// extractUserPromptsFromLines extracts user prompts from JSONL transcript lines.
   285→// IDE-injected context tags (like <ide_opened_file>) are stripped from the results.
   286→func extractUserPromptsFromLines(lines []string) []string {
   287→	var prompts []string
   288→	for _, line := range lines {
   289→		line = strings.TrimSpace(line)
   290→		if line == "" {
   291→			continue
   292→		}
   293→
   294→		var entry map[string]interface{}
   295→		if err := json.Unmarshal([]byte(line), &entry); err != nil {
   296→			continue
   297→		}
   298→
   299→		// Check for user message (supports both "human" and "user" types)
   300→		msgType, ok := entry["type"].(string)
   301→		if !ok || (msgType != "human" && msgType != "user") {
   302→			continue
   303→		}
   304→
   305→		// Extract message content
   306→		message, ok := entry["message"].(map[string]interface{})
   307→		if !ok {
   308→			continue
   309→		}
   310→
   311→		// Handle string content
   312→		if content, ok := message["content"].(string); ok && content != "" {
   313→			cleaned := textutil.StripIDEContextTags(content)
   314→			if cleaned != "" {
   315→				prompts = append(prompts, cleaned)
   316→			}
   317→			continue
   318→		}
   319→
   320→		// Handle array content (e.g., multiple text blocks from VSCode)
   321→		if arr, ok := message["content"].([]interface{}); ok {
   322→			var texts []string
   323→			for _, item := range arr {
   324→				if m, ok := item.(map[string]interface{}); ok {
   325→					if m["type"] == "text" {
   326→						if text, ok := m["text"].(string); ok {
   327→							texts = append(texts, text)
   328→						}
   329→					}
   330→				}
   331→			}
   332→			if len(texts) > 0 {
   333→				cleaned := textutil.StripIDEContextTags(strings.Join(texts, "\n\n"))
   334→				if cleaned != "" {
   335→					prompts = append(prompts, cleaned)
   336→				}
   337→			}
   338→		}
   339→	}
   340→	return prompts
   341→}
   342→
   343→// generateContextFromPrompts generates context.md content from a list of prompts.
   344→func generateContextFromPrompts(prompts []string) []byte {
   345→	if len(prompts) == 0 {
   346→		return nil
   347→	}
   348→
   349→	var buf strings.Builder
   350→	buf.WriteString("# Session Context\n\n")
   351→	buf.WriteString("## User Prompts\n\n")
   352→
   353→	for i, prompt := range prompts {
   354→		// Truncate very long prompts for readability
   355→		displayPrompt := prompt
   356→		if len(displayPrompt) > 500 {
   357→			displayPrompt = displayPrompt[:500] + "..."
   358→		}
   359→		buf.WriteString(fmt.Sprintf("### Prompt %d\n\n", i+1))
   360→		buf.WriteString(displayPrompt)
   361→		buf.WriteString("\n\n")
   362→	}
   363→
   364→	return []byte(buf.String())
   365→}
   366→

