package strategy

import (
	"strings"
	"time"

	"entire.io/cli/cmd/entire/cli/checkpoint"
	"github.com/go-git/go-git/v5/plumbing/object"
	"github.com/sergi/go-diff/diffmatchpatch"
)

// CalculateAttribution computes line-level attribution by diffing
// the checkpoint tree (agent work) against the committed tree (user's commit).
//
// This is a point-in-time calculation that produces a snapshot of how much
// of the committed code came from the agent unchanged vs human edits.
//
// Returns nil if filesTouched is empty.
func CalculateAttribution(
	checkpointTree *object.Tree,
	committedTree *object.Tree,
	filesTouched []string,
) *checkpoint.InitialAttribution {
	if len(filesTouched) == 0 {
		return nil
	}

	var totalUnchanged, totalAdded, totalRemoved, totalCommittedLines int

	for _, filePath := range filesTouched {
		checkpointContent := getFileContent(checkpointTree, filePath)
		committedContent := getFileContent(committedTree, filePath)

		// Skip if both are empty (file doesn't exist in either)
		if checkpointContent == "" && committedContent == "" {
			continue
		}

		unchanged, added, removed := diffLines(checkpointContent, committedContent)

		totalUnchanged += unchanged
		totalAdded += added
		totalRemoved += removed

		// Count lines in committed version
		if committedContent != "" {
			totalCommittedLines += countLines(committedContent)
		}
	}

	// Calculate percentage (avoid division by zero)
	var agentPercentage float64
	if totalCommittedLines > 0 {
		agentPercentage = float64(totalUnchanged) / float64(totalCommittedLines) * 100
	}

	// Estimate modified lines as min(added, removed)
	// This gives a rough approximation of lines that were changed vs purely added/removed
	humanModified := min(totalAdded, totalRemoved)
	humanAdded := totalAdded - humanModified
	humanRemoved := totalRemoved - humanModified

	return &checkpoint.InitialAttribution{
		CalculatedAt:    time.Now(),
		AgentLines:      totalUnchanged,
		HumanAdded:      humanAdded,
		HumanModified:   humanModified,
		HumanRemoved:    humanRemoved,
		TotalCommitted:  totalCommittedLines,
		AgentPercentage: agentPercentage,
	}
}

// getFileContent retrieves the content of a file from a tree.
// Returns empty string if the file doesn't exist or can't be read.
func getFileContent(tree *object.Tree, path string) string {
	if tree == nil {
		return ""
	}

	file, err := tree.File(path)
	if err != nil {
		return ""
	}

	content, err := file.Contents()
	if err != nil {
		return ""
	}

	// Skip binary files (contain null bytes)
	if strings.Contains(content, "\x00") {
		return ""
	}

	return content
}

// diffLines compares two strings and returns line-level diff stats.
// Returns (unchanged, added, removed) line counts.
func diffLines(checkpointContent, committedContent string) (unchanged, added, removed int) {
	// Handle edge cases
	if checkpointContent == committedContent {
		return countLines(committedContent), 0, 0
	}
	if checkpointContent == "" {
		return 0, countLines(committedContent), 0
	}
	if committedContent == "" {
		return 0, 0, countLines(checkpointContent)
	}

	dmp := diffmatchpatch.New()

	// Convert to line-based diff using DiffLinesToChars/DiffCharsToLines pattern
	text1, text2, lineArray := dmp.DiffLinesToChars(checkpointContent, committedContent)
	diffs := dmp.DiffMain(text1, text2, false)
	diffs = dmp.DiffCharsToLines(diffs, lineArray)

	for _, d := range diffs {
		lines := countLinesInText(d.Text)
		switch d.Type {
		case diffmatchpatch.DiffEqual:
			unchanged += lines
		case diffmatchpatch.DiffInsert:
			added += lines
		case diffmatchpatch.DiffDelete:
			removed += lines
		}
	}

	return unchanged, added, removed
}

// countLines returns the number of lines in content.
// An empty string has 0 lines. A string without newlines has 1 line.
func countLines(content string) int {
	if content == "" {
		return 0
	}
	lines := strings.Count(content, "\n")
	// If content doesn't end with newline, add 1 for the last line
	if !strings.HasSuffix(content, "\n") {
		lines++
	}
	return lines
}

// countLinesInText counts lines in a diff text segment.
// Similar to countLines but handles the diff output format.
func countLinesInText(text string) int {
	if text == "" {
		return 0
	}
	// Count newlines as line separators
	lines := strings.Count(text, "\n")
	// If text doesn't end with newline and is not empty, count the last line
	if !strings.HasSuffix(text, "\n") && len(text) > 0 {
		lines++
	}
	return lines
}

