   280→		t.Error("second checkpoint with identical content should be skipped")
   281→	}
   282→	if result2.CommitHash != result1.CommitHash {
   283→		t.Errorf("skipped checkpoint should return previous commit hash, got %s, want %s",
   284→			result2.CommitHash, result1.CommitHash)
   285→	}
   286→
   287→	// Modify the file and create another checkpoint - should NOT be skipped
   288→	if err := os.WriteFile(testFile, []byte("package main\n\nfunc main() {}\n"), 0o644); err != nil {
   289→		t.Fatalf("failed to modify test file: %v", err)
   290→	}
   291→
   292→	result3, err := store.WriteTemporary(context.Background(), WriteTemporaryOptions{
   293→		SessionID:         "test-session",
   294→		BaseCommit:        baseCommit,
   295→		ModifiedFiles:     []string{"test.go"},
   296→		MetadataDir:       ".entire/metadata/test-session",
   297→		MetadataDirAbs:    metadataDir,
   298→		CommitMessage:     "Checkpoint 3",
   299→		AuthorName:        "Test",
   300→		AuthorEmail:       "test@test.com",
   301→		IsFirstCheckpoint: false,
   302→	})
   303→	if err != nil {
   304→		t.Fatalf("WriteTemporary() third call error = %v", err)
   305→	}
   306→	if result3.Skipped {
   307→		t.Error("third checkpoint with modified content should NOT be skipped")
   308→	}
   309→	if result3.CommitHash == result1.CommitHash {
   310→		t.Error("third checkpoint should have a different commit hash than first")
   311→	}
   312→}
