   486→func TestShadowStrategy_CanRewind_DirtyRepo(t *testing.T) {
   487→	// For shadow, CanRewind always returns true because rewinding
   488→	// replaces local changes with checkpoint contents - that's the expected behavior.
   489→	// Users rewind to undo Claude's changes, which are uncommitted by definition.
   490→	// However, it now returns a warning message with diff stats.
   491→	dir := t.TempDir()
   492→	repo, err := git.PlainInit(dir, false)
   493→	if err != nil {
   494→		t.Fatalf("failed to init git repo: %v", err)
   495→	}
   496→
   497→	// Create initial commit
   498→	worktree, err := repo.Worktree()
   499→	if err != nil {
   500→		t.Fatalf("failed to get worktree: %v", err)
   501→	}
   502→	testFile := filepath.Join(dir, "test.txt")
   503→	if err := os.WriteFile(testFile, []byte("line1\nline2\nline3\n"), 0o644); err != nil {
   504→		t.Fatalf("failed to write test file: %v", err)
   505→	}
   506→	if _, err := worktree.Add("test.txt"); err != nil {
   507→		t.Fatalf("failed to add file: %v", err)
   508→	}
   509→	_, err = worktree.Commit("Initial commit", &git.CommitOptions{
   510→		Author: &object.Signature{Name: "Test", Email: "test@test.com"},
   511→	})
   512→	if err != nil {
   513→		t.Fatalf("failed to commit: %v", err)
   514→	}
   515→
   516→	// Make the repo dirty by modifying the file
   517→	if err := os.WriteFile(testFile, []byte("line1\nmodified line2\nline3\nnew line4\n"), 0o644); err != nil {
   518→		t.Fatalf("failed to modify test file: %v", err)
   519→	}
   520→
   521→	t.Chdir(dir)
   522→
   523→	s := NewManualCommitStrategy()
   524→	can, reason, err := s.CanRewind()
   525→	if err != nil {
   526→		t.Errorf("CanRewind() error = %v", err)
   527→	}
   528→	if !can {
   529→		t.Error("CanRewind() = false, want true (shadow always allows rewind)")
   530→	}
   531→	// Now we expect a warning message with diff stats
   532→	if reason == "" {
   533→		t.Error("CanRewind() reason is empty, want warning about uncommitted changes")
   534→	}
   535→	if !strings.Contains(reason, "uncommitted changes will be reverted") {
   536→		t.Errorf("CanRewind() reason = %q, want to contain 'uncommitted changes will be reverted'", reason)
   537→	}
   538→	if !strings.Contains(reason, "test.txt") {
   539→		t.Errorf("CanRewind() reason = %q, want to contain filename 'test.txt'", reason)
   540→	}
   541→}
