   928→func TestShadowStrategy_FilesTouched_OnlyModifiedFiles(t *testing.T) {
   929→	// This test verifies that files_touched only contains files that were actually
   930→	// modified during the session, not ALL files in the repository.
   931→	//
   932→	// The fix tracks files in SessionState.FilesTouched as they are modified,
   933→	// rather than collecting all files from the shadow branch tree.
   934→
   935→	dir := t.TempDir()
   936→	repo, err := git.PlainInit(dir, false)
   937→	if err != nil {
   938→		t.Fatalf("failed to init git repo: %v", err)
   939→	}
   940→
   941→	// Create initial commit with multiple pre-existing files
   942→	worktree, err := repo.Worktree()
   943→	if err != nil {
   944→		t.Fatalf("failed to get worktree: %v", err)
   945→	}
   946→
   947→	// Create 3 pre-existing files that should NOT be in files_touched
   948→	preExistingFiles := []string{"existing1.txt", "existing2.txt", "existing3.txt"}
   949→	for _, f := range preExistingFiles {
   950→		filePath := filepath.Join(dir, f)
   951→		if err := os.WriteFile(filePath, []byte("original content of "+f), 0o644); err != nil {
   952→			t.Fatalf("failed to write file %s: %v", f, err)
   953→		}
   954→		if _, err := worktree.Add(f); err != nil {
   955→			t.Fatalf("failed to add file %s: %v", f, err)
   956→		}
   957→	}
   958→
   959→	_, err = worktree.Commit("Initial commit with pre-existing files", &git.CommitOptions{
   960→		Author: &object.Signature{Name: "Test", Email: "test@test.com", When: time.Now()},
   961→	})
   962→	if err != nil {
   963→		t.Fatalf("failed to commit: %v", err)
   964→	}
   965→
   966→	t.Chdir(dir)
   967→
   968→	s := &ManualCommitStrategy{}
   969→	sessionID := "2025-01-15-test-session-123"
   970→
   971→	// Create metadata directory with a transcript
   972→	metadataDir := ".entire/metadata/" + sessionID
   973→	metadataDirAbs := filepath.Join(dir, metadataDir)
   974→	if err := os.MkdirAll(metadataDirAbs, 0o755); err != nil {
   975→		t.Fatalf("failed to create metadata dir: %v", err)
   976→	}
   977→
   978→	// Write transcript file (minimal valid JSONL)
   979→	transcript := `{"type":"human","message":{"content":"modify existing1.txt"}}
   980→{"type":"assistant","message":{"content":"I'll modify existing1.txt for you."}}
   981→`
   982→	if err := os.WriteFile(filepath.Join(metadataDirAbs, paths.TranscriptFileName), []byte(transcript), 0o644); err != nil {
   983→		t.Fatalf("failed to write transcript: %v", err)
   984→	}
   985→
   986→	// First checkpoint using SaveChanges - captures ALL working directory files
   987→	// (for rewind purposes), but tracks only modified files in FilesTouched
   988→	err = s.SaveChanges(SaveContext{
   989→		SessionID:      sessionID,
   990→		ModifiedFiles:  []string{}, // No files modified yet
   991→		NewFiles:       []string{},
   992→		DeletedFiles:   []string{},
   993→		MetadataDir:    metadataDir,
   994→		MetadataDirAbs: metadataDirAbs,
   995→		CommitMessage:  "Checkpoint 1",
   996→		AuthorName:     "Test",
   997→		AuthorEmail:    "test@test.com",
   998→	})
   999→	if err != nil {
  1000→		t.Fatalf("SaveChanges() error = %v", err)
  1001→	}
  1002→
  1003→	// Now simulate a second checkpoint where ONLY existing1.txt is modified
  1004→	// (but NOT existing2.txt or existing3.txt)
  1005→	modifiedContent := []byte("MODIFIED content of existing1.txt")
  1006→	if err := os.WriteFile(filepath.Join(dir, "existing1.txt"), modifiedContent, 0o644); err != nil {
  1007→		t.Fatalf("failed to modify existing1.txt: %v", err)
  1008→	}
  1009→
  1010→	// Second checkpoint using SaveChanges - only modified file should be tracked
  1011→	err = s.SaveChanges(SaveContext{
  1012→		SessionID:      sessionID,
  1013→		ModifiedFiles:  []string{"existing1.txt"}, // Only this file was modified
  1014→		NewFiles:       []string{},
  1015→		DeletedFiles:   []string{},
  1016→		MetadataDir:    metadataDir,
  1017→		MetadataDirAbs: metadataDirAbs,
  1018→		CommitMessage:  "Checkpoint 2",
  1019→		AuthorName:     "Test",
  1020→		AuthorEmail:    "test@test.com",
  1021→	})
  1022→	if err != nil {
  1023→		t.Fatalf("SaveChanges() error = %v", err)
  1024→	}
  1025→
  1026→	// Load session state to verify FilesTouched
  1027→	state, err := s.loadSessionState(sessionID)
  1028→	if err != nil {
  1029→		t.Fatalf("loadSessionState() error = %v", err)
  1030→	}
  1031→
  1032→	// Now condense the session
  1033→	checkpointID := id.MustCheckpointID("a1b2c3d4e5f6")
  1034→	result, err := s.CondenseSession(repo, checkpointID, state)
  1035→	if err != nil {
  1036→		t.Fatalf("CondenseSession() error = %v", err)
  1037→	}
  1038→
  1039→	// Verify that files_touched only contains the file that was actually modified
  1040→	expectedFilesTouched := []string{"existing1.txt"}
  1041→
  1042→	// Check what we actually got
  1043→	if len(result.FilesTouched) != len(expectedFilesTouched) {
  1044→		t.Errorf("FilesTouched contains %d files, want %d.\nGot: %v\nWant: %v",
  1045→			len(result.FilesTouched), len(expectedFilesTouched),
  1046→			result.FilesTouched, expectedFilesTouched)
  1047→	}
  1048→
  1049→	// Verify the exact content
  1050→	filesTouchedMap := make(map[string]bool)
  1051→	for _, f := range result.FilesTouched {
  1052→		filesTouchedMap[f] = true
  1053→	}
  1054→
  1055→	// Check that ONLY the modified file is in files_touched
  1056→	for _, expected := range expectedFilesTouched {
  1057→		if !filesTouchedMap[expected] {
  1058→			t.Errorf("Expected file %q to be in files_touched, but it was not. Got: %v", expected, result.FilesTouched)
  1059→		}
  1060→	}
  1061→
  1062→	// Check that pre-existing unmodified files are NOT in files_touched
  1063→	unmodifiedFiles := []string{"existing2.txt", "existing3.txt"}
  1064→	for _, unmodified := range unmodifiedFiles {
  1065→		if filesTouchedMap[unmodified] {
  1066→			t.Errorf("File %q should NOT be in files_touched (it was not modified during the session), but it was included. Got: %v",
  1067→				unmodified, result.FilesTouched)
  1068→		}
  1069→	}
  1070→}
