	if err != nil {
		t.Fatalf("CondenseSession() error = %v", err)
	}

	// Verify CondenseResult
	if result.CheckpointID != checkpointID {
		t.Errorf("CheckpointID = %q, want %q", result.CheckpointID, checkpointID)
	}

