// is correctly written to metadata.json when provided, and omitted when nil.
func TestWriteCommitted_InitialAttribution(t *testing.T) {
	t.Run("with attribution (manual-commit)", func(t *testing.T) {
		repo, _ := setupBranchTestRepo(t)
		store := NewGitStore(repo)

		checkpointID := id.MustCheckpointID("c3d4e5f6a7b8")

		// Write checkpoint with InitialAttribution (like manual-commit does)
		err := store.WriteCommitted(context.Background(), WriteCommittedOptions{
			CheckpointID: checkpointID,
			SessionID:    "test-session-manual",
			Strategy:     "manual-commit",
			Transcript:   []byte("test transcript"),
			AuthorName:   "Test Author",
			AuthorEmail:  "test@example.com",
			InitialAttribution: &InitialAttribution{
				AgentLines:      100,
				HumanAdded:      10,
				HumanModified:   5,
				HumanRemoved:    2,
				TotalCommitted:  110,
				AgentPercentage: 90.9,
			},
		})
		if err != nil {
			t.Fatalf("WriteCommitted() error = %v", err)
		}

		// Read metadata.json and verify InitialAttribution is present
		metadata := readMetadataJSON(t, repo, checkpointID)

		if metadata.InitialAttribution == nil {
			t.Fatal("expected InitialAttribution to be present, got nil")
		}
