			t.Errorf("AgentLines = %d, want 100", metadata.InitialAttribution.AgentLines)
		}
		if metadata.InitialAttribution.HumanAdded != 10 {
			t.Errorf("HumanAdded = %d, want 10", metadata.InitialAttribution.HumanAdded)
		}
