			t.Errorf("HumanModified = %d, want 5", metadata.InitialAttribution.HumanModified)
		}
		if metadata.InitialAttribution.HumanRemoved != 2 {
			t.Errorf("HumanRemoved = %d, want 2", metadata.InitialAttribution.HumanRemoved)
		}
		if metadata.InitialAttribution.TotalCommitted != 110 {
			t.Errorf("TotalCommitted = %d, want 110", metadata.InitialAttribution.TotalCommitted)
		}
		if metadata.InitialAttribution.AgentPercentage != 90.9 {
			t.Errorf("AgentPercentage = %f, want 90.9", metadata.InitialAttribution.AgentPercentage)
		}
	})

