// calculatePromptAttributionForSave calculates attribution at the start of a checkpoint save.
// This captures user edits since the last checkpoint BEFORE the agent's changes are saved.
func (s *ManualCommitStrategy) calculatePromptAttributionForSave(
	repo *git.Repository,
	state *SessionState,
	ctx SaveContext,
) PromptAttribution {
	nextCheckpointNum := state.CheckpointCount + 1

	// Get base tree (the commit when session started)
	var baseTree *object.Tree
	if baseCommit, err := repo.CommitObject(plumbing.NewHash(state.BaseCommit)); err == nil {
		baseTree, _ = baseCommit.Tree()
	}

	// Get last checkpoint tree (shadow branch, if exists)
	var lastCheckpointTree *object.Tree
	if state.CheckpointCount > 0 {
		shadowBranchName := checkpoint.ShadowBranchNameForCommit(state.BaseCommit)
		refName := plumbing.NewBranchReferenceName(shadowBranchName)
		if ref, err := repo.Reference(refName, true); err == nil {
			if commit, err := repo.CommitObject(ref.Hash()); err == nil {
				lastCheckpointTree, _ = commit.Tree()
			}
		}
	}

	// Build worktree files map from the files being saved
	// We need to read the current content of these files
	worktreeFiles := make(map[string]string)
	worktree, err := repo.Worktree()
	if err != nil {
		// Can't access worktree, return empty attribution
		return PromptAttribution{CheckpointNumber: nextCheckpointNum}
	}

	// Get worktree root path
	worktreeRoot := worktree.Filesystem.Root()

	// Read content of modified and new files
	allFiles := append(ctx.ModifiedFiles, ctx.NewFiles...)
	for _, filePath := range allFiles {
		fullPath := filepath.Join(worktreeRoot, filePath)
		content, err := os.ReadFile(fullPath)
		if err != nil {
			continue // Skip files we can't read
		}
		worktreeFiles[filePath] = string(content)
	}

	// Also include deleted files with empty content (so we can track removals)
	for _, filePath := range ctx.DeletedFiles {
		worktreeFiles[filePath] = ""
	}

	return CalculatePromptAttribution(baseTree, lastCheckpointTree, worktreeFiles, nextCheckpointNum)
}

