	state.FilesTouched = mergeFilesTouched(state.FilesTouched, ctx.ModifiedFiles, ctx.NewFiles, ctx.DeletedFiles)

	// Save updated state
	if err := s.saveSessionState(state); err != nil {
		return fmt.Errorf("failed to save session state: %w", err)
	}

	if !branchExisted {
		fmt.Fprintf(os.Stderr, "Created shadow branch '%s' and committed task checkpoint\n", shadowBranchName)
	} else {
		fmt.Fprintf(os.Stderr, "Committed task checkpoint to shadow branch '%s'\n", shadowBranchName)
	}

	// Log task checkpoint creation
	logCtx := logging.WithComponent(context.Background(), "checkpoint")
	attrs := []any{
		slog.String("strategy", "manual-commit"),
		slog.String("checkpoint_type", "task"),
		slog.String("checkpoint_uuid", ctx.CheckpointUUID),
		slog.String("tool_use_id", ctx.ToolUseID),
		slog.String("subagent_type", ctx.SubagentType),
		slog.Int("modified_files", len(ctx.ModifiedFiles)),
		slog.Int("new_files", len(ctx.NewFiles)),
		slog.Int("deleted_files", len(ctx.DeletedFiles)),
		slog.String("shadow_branch", shadowBranchName),
		slog.Bool("branch_created", !branchExisted),
	}
	if ctx.IsIncremental {
		attrs = append(attrs,
			slog.Bool("is_incremental", true),
			slog.String("incremental_type", ctx.IncrementalType),
			slog.Int("incremental_sequence", ctx.IncrementalSequence),
		)
	}
	logging.Info(logCtx, "task checkpoint saved", attrs...)

	return nil
}

// mergeFilesTouched merges multiple file lists into existing touched files, deduplicating.
func mergeFilesTouched(existing []string, fileLists ...[]string) []string {
	seen := make(map[string]bool)
	for _, f := range existing {
		seen[f] = true
	}

	for _, list := range fileLists {
		for _, f := range list {
			seen[f] = true
		}
	}

	result := make([]string, 0, len(seen))
	for f := range seen {
		result = append(result, f)
	}

	// Sort for deterministic output
	sort.Strings(result)
	return result
}

// accumulateTokenUsage adds new token usage to existing accumulated usage.
// If existing is nil, returns a copy of incoming. If incoming is nil, returns existing unchanged.
func accumulateTokenUsage(existing, incoming *agent.TokenUsage) *agent.TokenUsage {
	if incoming == nil {
		return existing
	}
	if existing == nil {
		// Return a copy to avoid sharing the pointer
		return &agent.TokenUsage{
			InputTokens:         incoming.InputTokens,
			CacheCreationTokens: incoming.CacheCreationTokens,
			CacheReadTokens:     incoming.CacheReadTokens,
			OutputTokens:        incoming.OutputTokens,
			APICallCount:        incoming.APICallCount,
			SubagentTokens:      incoming.SubagentTokens,
		}
	}

	// Accumulate values
	existing.InputTokens += incoming.InputTokens
	existing.CacheCreationTokens += incoming.CacheCreationTokens
	existing.CacheReadTokens += incoming.CacheReadTokens
	existing.OutputTokens += incoming.OutputTokens
	existing.APICallCount += incoming.APICallCount

	// Accumulate subagent tokens if present
	if incoming.SubagentTokens != nil {
		existing.SubagentTokens = accumulateTokenUsage(existing.SubagentTokens, incoming.SubagentTokens)
	}

	return existing
}

// deleteShadowBranch deletes a shadow branch by name using an existing repo handle.
// Returns nil if the branch doesn't exist (idempotent).
func deleteShadowBranch(repo *git.Repository, branchName string) error {
	refName := plumbing.NewBranchReferenceName(branchName)

	// Check if reference exists
	ref, err := repo.Reference(refName, true)
	if err != nil {
		// Branch doesn't exist - nothing to delete (idempotent)
		return nil //nolint:nilerr // Not an error condition - branch already gone
	}

	// Delete the reference
	if err := repo.Storer.RemoveReference(ref.Name()); err != nil {
		return fmt.Errorf("failed to delete branch %s: %w", branchName, err)
	}

	return nil
}

// calculatePromptAttributionForSave calculates attribution at checkpoint save time.
// This detects user edits since the last checkpoint for files the agent is NOT touching.
//
// The key insight: at SaveChanges time, the worktree contains agent's changes mixed with
// any user edits. We separate them by:
// 1. Files in ctx.ModifiedFiles/NewFiles/DeletedFiles = agent is touching these
// 2. Other files that changed since last checkpoint = user edits between prompts
//
// For files the agent IS touching, we can't distinguish user edits made before the agent
// worked (the worktree has both mixed). Those will be detected by the final attribution
// at commit time (shadow → committed diff).
func (s *ManualCommitStrategy) calculatePromptAttributionForSave(
	repo *git.Repository,
	state *SessionState,
	ctx SaveContext,
) PromptAttribution {
	nextCheckpointNum := state.CheckpointCount + 1

	// Get base tree (the commit when session started)
	var baseTree *object.Tree
	if baseCommit, err := repo.CommitObject(plumbing.NewHash(state.BaseCommit)); err == nil {
		baseTree, _ = baseCommit.Tree()
	}

	// Get last checkpoint tree (shadow branch, if exists)
	var lastCheckpointTree *object.Tree
	if state.CheckpointCount > 0 {
		shadowBranchName := checkpoint.ShadowBranchNameForCommit(state.BaseCommit)
		refName := plumbing.NewBranchReferenceName(shadowBranchName)
		if ref, err := repo.Reference(refName, true); err == nil {
			if commit, err := repo.CommitObject(ref.Hash()); err == nil {
				lastCheckpointTree, _ = commit.Tree()
			}
		}
	}

	worktree, err := repo.Worktree()
	if err != nil {
		return PromptAttribution{CheckpointNumber: nextCheckpointNum}
	}

	// Build set of files the agent is touching in this checkpoint
	agentFiles := make(map[string]bool)
	for _, f := range ctx.ModifiedFiles {
		agentFiles[f] = true
	}
	for _, f := range ctx.NewFiles {
		agentFiles[f] = true
	}
	for _, f := range ctx.DeletedFiles {
		agentFiles[f] = true
	}

	// Get worktree status to find ALL changed files
	status, err := worktree.Status()
	if err != nil {
		return PromptAttribution{CheckpointNumber: nextCheckpointNum}
	}

	worktreeRoot := worktree.Filesystem.Root()

	// Build map of user-changed files (files that changed but agent is NOT touching)
	userFiles := make(map[string]string)
	for filePath, fileStatus := range status {
		// Skip files the agent is touching
		if agentFiles[filePath] {
			continue
		}
		// Skip unmodified files
		if fileStatus.Worktree == git.Unmodified && fileStatus.Staging == git.Unmodified {
			continue
		}
		// This file changed but agent isn't touching it = user edit
		fullPath := filepath.Join(worktreeRoot, filePath)
		content, err := os.ReadFile(fullPath)
		if err != nil {
			userFiles[filePath] = "" // File deleted or unreadable
		} else {
			userFiles[filePath] = string(content)
		}
	}

	// Also check files in state.FilesTouched that might have been edited by user
	// These are files the agent touched in previous checkpoints that user might have edited
	for _, filePath := range state.FilesTouched {
		if agentFiles[filePath] {
			continue // Agent touching it this checkpoint
		}
		if _, already := userFiles[filePath]; already {
			continue // Already detected
		}
		// Check if this file changed since last checkpoint
		referenceTree := lastCheckpointTree
		if referenceTree == nil {
			referenceTree = baseTree
		}
		referenceContent := getFileContentFromTree(referenceTree, filePath)
		fullPath := filepath.Join(worktreeRoot, filePath)
		content, err := os.ReadFile(fullPath)
		currentContent := ""
		if err == nil {
			currentContent = string(content)
		}
		if currentContent != referenceContent {
			userFiles[filePath] = currentContent
		}
	}

	return CalculatePromptAttribution(baseTree, lastCheckpointTree, userFiles, nextCheckpointNum)
}

// getFileContentFromTree retrieves file content from a git tree.
func getFileContentFromTree(tree *object.Tree, path string) string {
	if tree == nil {
		return ""
	}
	file, err := tree.File(path)
	if err != nil {
		return ""
	}
	content, err := file.Contents()
	if err != nil {
		return ""
	}
	return content
}

