		if err == nil {
			currentContent = string(content)
		}
		if currentContent != referenceContent {
			userFiles[filePath] = currentContent
		}
	}

	return CalculatePromptAttribution(baseTree, lastCheckpointTree, userFiles, nextCheckpointNum)
}

