// getFileContentFromTree retrieves file content from a git tree.
func getFileContentFromTree(tree *object.Tree, path string) string {
	if tree == nil {
		return ""
	}
	file, err := tree.File(path)
	if err != nil {
		return ""
	}
	content, err := file.Contents()
	if err != nil {
		return ""
	}
	return content
}

